// Config for dynamic discovery
return {
  json: {
    rawBaseUrl: 'https://raw.githubusercontent.com/Squidgy-AI/squidgy_updated_ui/main/knowledge_base',
    apiBaseUrl: 'https://api.github.com/repos/Squidgy-AI/squidgy_updated_ui/contents/knowledge_base',
    // Agents that have their OWN actions files (don't inherit shared actions)
    agentsWithOwnActions: ['personal_assistant']
  }
};

// Extract shared .md files
const config = $('Config').first().json;
const sharedFiles = $('Fetch Shared Folder').first().json;

const files = [];

// Get all .md files from shared folder
if (Array.isArray(sharedFiles)) {
  for (const file of sharedFiles) {
    if (file.name && file.name.endsWith('.md')) {
      files.push({
        source_file: file.name,
        url: `${config.rawBaseUrl}/shared/${file.name}`
      });
    }
  }
}

return { json: { sharedFiles: files, config } };

// Extract agent folder names
const agentFolders = $('Fetch Agents Folder').first().json;

const agents = [];

if (Array.isArray(agentFolders)) {
  for (const folder of agentFolders) {
    if (folder.type === 'dir' && folder.name) {
      agents.push({ agent_id: folder.name });
    }
  }
}

return agents.map(a => ({ json: a }));

// Build complete file list for this agent
const config = $('Config').first().json;
const sharedData = $('Parse Shared Files').first().json;
const agentId = $('Parse Agent Folders').item.json.agent_id;
const agentFiles = $input.first().json;

const files = [];

// 1. Add agent's own files
if (Array.isArray(agentFiles)) {
  for (const file of agentFiles) {
    if (file.name && file.name.endsWith('.md')) {
      files.push({
        agent_id: agentId,
        source_file: file.name,
        url: `${config.rawBaseUrl}/agents/${agentId}/${file.name}`
      });
    }
  }
}

// 2. Add shared files
// Check if this agent has its own actions files
const hasOwnActions = config.agentsWithOwnActions.includes(agentId);
const agentOwnFiles = files.map(f => f.source_file);

for (const sharedFile of sharedData.sharedFiles) {
  // Skip shared actions if agent has own actions
  if (hasOwnActions && (sharedFile.source_file === 'actions_performed.md' || sharedFile.source_file === 'actions_todo.md')) {
    continue;
  }

  // Skip if agent already has this file (own version takes precedence)
  if (agentOwnFiles.includes(sharedFile.source_file)) {
    continue;
  }

  files.push({
    agent_id: agentId,
    source_file: sharedFile.source_file,
    url: sharedFile.url
  });
}

// Also add shared files with agent_id='shared' for reference
const sharedRefFiles = sharedData.sharedFiles.map(f => ({
  agent_id: 'shared',
  source_file: f.source_file,
  url: f.url
}));

return [...files, ...sharedRefFiles].map(f => ({ json: f }));

// Deduplicate: shared files only need to be added once
const allItems = $input.all();
const seen = new Set();
const unique = [];

for (const item of allItems) {
  const key = `${item.json.agent_id}|${item.json.source_file}`;
  if (!seen.has(key)) {
    seen.add(key);
    unique.push(item);
  }
}

return unique;

const input = $input.first().json;
const prevData = $('Deduplicate Files').item.json;

// Get the document content
const document = typeof input === 'string' ? input : (input.data || input.body || JSON.stringify(input));

return {
  json: {
    agent_id: prevData.agent_id,
    source_file: prevData.source_file,
    document: document
  }
};

const items = $input.all();

// Count by agent
const agentCounts = {};
for (const item of items) {
  const agentId = item.json?.agent_id || 'unknown';
  agentCounts[agentId] = (agentCounts[agentId] || 0) + 1;
}

return {
  json: {
    success: true,
    total_files_processed: items.length,
    by_agent: agentCounts,
    timestamp: new Date().toISOString()
  }
};
